using System.Diagnostics;
using System.Runtime.InteropServices;
using TextAnalysis;

// Build a reproducible corpus
var baseWords = new[] {
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "benchmarking", "performance", "analysis", "dotnet", "upgrade",
    "framework", "optimization", "infrastructure", "methodology",
    "a", "an", "is", "to", "of", "in", "for", "on", "with", "at"
};
var rng = new Random(42);
var parts = new string[10_000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = baseWords[rng.Next(baseWords.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', parts));

string tfm = RuntimeInformation.FrameworkDescription;
Console.WriteLine($"Runtime: {tfm}");
Console.WriteLine($"Corpus: {analyzer.WordCount} words");
Console.WriteLine();

Benchmark("AverageWordLength", () => analyzer.AverageWordLength());
Benchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Benchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

static void Benchmark(string name, Action action, int warmup = 500, int iterations = 10_000)
{
    // Warmup
    for (int i = 0; i < warmup; i++) action();

    // Collect multiple runs for statistics
    const int runs = 5;
    double[] medians = new double[runs];

    for (int r = 0; r < runs; r++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < iterations; i++) action();
        sw.Stop();
        medians[r] = sw.Elapsed.TotalNanoseconds / iterations;
    }

    Array.Sort(medians);
    double median = medians[runs / 2];
    double min = medians[0];
    double max = medians[runs - 1];

    Console.WriteLine($"{name,-25} median: {median,10:F2} ns   min: {min,10:F2} ns   max: {max,10:F2} ns");
}

